SELECT order_id AS orderId, order_history AS orderHistory, sample_id AS sampleId, sample_type AS sampleType, sample_position AS samplePosition, primer, primer_type AS primerType, primer_position AS primerPosition, primer_concentration AS primerConcentration, seq, project, carrier_name AS carrierName, antibiotic_type AS antibioticType, plasmid_length AS plasmidLength, fragment_size AS fragmentSize, test_result AS testResult, origin_concentration AS originConcentration, template_plate_no AS templatePlateNo, template_hole_no AS templateHoleNo, performance, return_state AS returnState, flow_name AS flowName, plate_no AS plateNo, hole_no AS holeNo, belong_company AS belongCompany, produce_company AS produceCompany, produce_id AS produceId, hole_number AS holeNumber, layout, create_user AS createUser, create_time AS createTime, remark FROM yk_sample_info
AND order_id LIKE CONCAT('%', #{query.orderId}, '%')
AND order_history LIKE CONCAT('%', #{query.orderHistory}, '%')
AND sample_id LIKE CONCAT('%', #{query.sampleId}, '%')
AND sample_type = #{query.sampleType}
AND primer LIKE CONCAT('%', #{query.primer}, '%')
AND primer_type = #{query.primerType}
AND project = #{query.project}
AND carrier_name LIKE CONCAT('%', #{query.carrierName}, '%')
AND antibiotic_type = #{query.antibioticType}
AND test_result = #{query.testResult}
AND performance = #{query.performance}
AND return_state = #{query.returnState}
AND flow_name LIKE CONCAT('%', #{query.flowName}, '%')
AND plate_no LIKE CONCAT('%', #{query.plateNo}, '%')
AND belong_company LIKE CONCAT('%', #{query.belongCompany}, '%')
AND produce_company LIKE CONCAT('%', #{query.produceCompany}, '%')
AND produce_id = #{query.produceId}
AND create_user LIKE CONCAT('%', #{query.createUser}, '%')
ORDER BY create_time DESC

SELECT order_id AS orderId, order_history AS orderHistory, sample_id AS sampleId, sample_type AS sampleType, sample_position AS samplePosition, primer, primer_type AS primerType, primer_position AS primerPosition, primer_concentration AS primerConcentration, seq, project, carrier_name AS carrierName, antibiotic_type AS antibioticType, plasmid_length AS plasmidLength, fragment_size AS fragmentSize, test_result AS testResult, origin_concentration AS originConcentration, template_plate_no AS templatePlateNo, template_hole_no AS templateHoleNo, performance, return_state AS returnState, flow_name AS flowName, plate_no AS plateNo, hole_no AS holeNo, belong_company AS belongCompany, produce_company AS produceCompany, produce_id AS produceId, hole_number AS holeNumber, layout, create_user AS createUser, create_time AS createTime, remark FROM yk_sample_info
AND order_id LIKE CONCAT('%', #{query.orderId}, '%')
AND order_history LIKE CONCAT('%', #{query.orderHistory}, '%')
AND sample_id LIKE CONCAT('%', #{query.sampleId}, '%')
AND sample_type = #{query.sampleType}
AND primer LIKE CONCAT('%', #{query.primer}, '%')
AND primer_type = #{query.primerType}
AND project = #{query.project}
AND carrier_name LIKE CONCAT('%', #{query.carrierName}, '%')
AND antibiotic_type = #{query.antibioticType}
AND test_result = #{query.testResult}
AND performance = #{query.performance}
AND return_state = #{query.returnState}
AND flow_name LIKE CONCAT('%', #{query.flowName}, '%')
AND plate_no LIKE CONCAT('%', #{query.plateNo}, '%')
AND belong_company LIKE CONCAT('%', #{query.belongCompany}, '%')
AND produce_company LIKE CONCAT('%', #{query.produceCompany}, '%')
AND produce_id = #{query.produceId}
AND create_user LIKE CONCAT('%', #{query.createUser}, '%')
ORDER BY create_time DESC

SELECT s.order_id AS orderId, COUNT(*) AS templateNumber, MAX(c.customer_name) AS customerName, MAX(c.address) AS customerAddress, s.sample_id AS sampleId, MAX(s.sample_type) AS sampleType, MAX(s.primer) AS primer, MAX(s.primer_concentration) AS primerConcentration, MAX(s.carrier_name) AS carrierName, MAX(s.antibiotic_type) AS antibioticType, MAX(s.fragment_size) AS fragmentSize, MAX(s.test_result) AS testResult, MAX(s.origin_concentration) AS originConcentration, MAX(s.template_plate_no) AS templatePlateNo, MAX(s.template_hole_no) AS templateHoleNo, MAX(s.performance) AS performance, MAX(s.return_state) AS returnState, MAX(s.flow_name) AS flowName, MAX(s.create_user) AS createUser, MAX(s.remark) AS remark FROM yk_sample_info s LEFT JOIN yk_order_info o ON s.order_id = o.order_id LEFT JOIN yk_customer_info c ON o.customer_id = c.id where flow_name = '0'
AND s.order_id = #{query.orderId}
AND s.sample_id = #{query.sampleId}
AND c.customer_name LIKE CONCAT('%', #{query.customerName}, '%')
AND s.return_state = #{query.returnState}
GROUP BY s.order_id, s.sample_id ORDER BY MAX(s.create_time) DESC

SELECT c.customer_name AS customerName, s.produce_id AS produceId, s.sample_id AS sampleId, s.fragment_size AS fragmentSize FROM yk_sample_info s LEFT JOIN yk_order_info o ON s.order_id = o.order_id LEFT JOIN yk_customer_info c ON o.customer_id = c.id
AND s.order_id >= #{req.startOrderNo}
AND s.order_id <= #{req.endOrderNo}
AND s.belong_company = #{req.belongCompany}
ORDER BY s.order_id, s.sample_id

SELECT s.produce_id AS produceId, s.origin_hole_no AS originHoleNo, c.customer_name AS customerName, s.return_state AS returnState, s.sample_type AS sampleType, s.sample_id AS sampleId, s.carrier_name AS carrierName, s.antibiotic_type AS antibioticType, s.sample_position AS samplePosition, s.remark AS remark FROM yk_sample_info s LEFT JOIN yk_order_info o ON s.order_id = o.order_id LEFT JOIN yk_customer_info c ON o.customer_id = c.id
AND s.return_state IN ('模板重抽', '报告重抽')
AND s.template_plate_no IN
#{plateNo}
AND s.belong_lab = #{req.belongLab}
ORDER BY s.template_plate_no, s.template_hole_no
